    {
        let name = v8::String::new(scope, "readTensor").unwrap();
        let func_tmpl = v8::FunctionTemplate::builder_raw(ml_context_op_4).build(scope);
        func_tmpl.set_class_name(name);
        proto.set(name.into(), func_tmpl.into());
    }
    // method: readTensor()
    {
        let name = v8::String::new(scope, "readTensor").unwrap();
        let func_tmpl = v8::FunctionTemplate::builder_raw(ml_context_op_5).build(scope);
        func_tmpl.set_class_name(name);
        proto.set(name.into(), func_tmpl.into());
    }
    // method: writeTensor()
